SELECT * FROM check_in
WHERE user_id = #{userId} AND child_id = #{childId}
AND check_in_date = #{checkInDate} LIMIT 1

SELECT IFNULL(MAX(streak_days), 0) FROM check_in
WHERE user_id = #{userId} AND child_id = #{childId}
AND check_in_date = (
    SELECT MAX(check_in_date) FROM check_in
    WHERE user_id = #{userId} AND child_id = #{childId}
)

SELECT * FROM check_in
WHERE user_id = #{userId} AND child_id = #{childId}
AND YEAR(check_in_date) = #{year} AND MONTH(check_in_date) = #{month}
ORDER BY check_in_date ASC
